import pytest
import uuid
from <helper_fn> import get_admin_token, get_audit_record
from <helper_fn> import api_post, api_get

@pytest.fixture
def admin_token():
    return get_admin_token()

@pytest.fixture
def created_run_id(admin_token):
    ids = []
    yield ids
    for rid in ids:
        api_post("/payroll-runs/" + rid + "/cancel", token=admin_token)

def test_admin_creates_payroll_run_all_valid_fields(admin_token, created_run_id):
    payload = {
        "name": "PR-" + str(uuid.uuid4())[:8],
        "period_start": "2024-01-01",
        "period_end": "2024-01-31",
        "pay_date": "2024-02-05",
        "department_id": <fixture>["department_id"]
    }
    resp = api_post("/payroll-runs", json=payload, token=admin_token)
    assert resp.status_code in (200, 201)
    body = resp.json()
    assert "id" in body and body["id"]
    created_run_id.append(body["id"])
    audit = get_audit_record(entity="payroll-run", entity_id=body["id"])
    assert audit is not None, "Audit record must be written on success"

import pytest
from <helper_fn> import get_admin_token, api_post

@pytest.fixture
def admin_token():
    return get_admin_token()

def test_create_payroll_run_missing_mandatory_field_returns_400(admin_token):
    payload = {
        "name": "PR-missing-start",
        "period_end": "2024-01-31",
        "pay_date": "2024-02-05",
        "department_id": <fixture>["department_id"]
    }
    resp = api_post("/payroll-runs", json=payload, token=admin_token)
    assert resp.status_code == 400
    body = resp.json()
    errors = str(body).lower()
    assert "period_start" in errors, "Validation error must reference missing field"

